1	//! The `finalize` subcommand: squash + set-bookmark + push a jj
2	//! repo, optionally detached so trailing writes land first.
3	//!
4	//! Built for the bot to atomically finalize its `.claude` session
5	//! repo at end-of-step. Every action is opt-in (`--squash`,
6	//! `--push`, `--detach`, `--delay`). The detached path re-execs
7	//! `vc-x1 finalize --exec …` so its output and errors survive the
8	//! parent exiting; failures are dropped as markers under
9	//! `~/.cache/vc-x1/finalize-status` and surfaced on the next
10	//! `vc-x1` run.
11	
12	use std::path::{Path, PathBuf};
13	use std::process::Stdio;
14	use std::time::{SystemTime, UNIX_EPOCH};
15	
16	use clap::Args;
17	use log::{debug, info};
18	
19	use crate::common::run;
20	use crate::context::Context;
21	use crate::options_flags::squash::{SquashOption, SquashSpec};
22	
23	/// Directory where the detached finalize child writes failure markers.
24	/// A subsequent `vc-x1` invocation scans this directory and surfaces
25	/// any failures to the user, closing the gap that the detached child's
26	/// non-zero exit isn't observable by the caller.
27	fn status_dir() -> Option<PathBuf> {
28	    std::env::var_os("HOME").map(|h| PathBuf::from(h).join(".cache/vc-x1/finalize-status"))
29	}
30	
31	/// Drop a failure marker for the detached child whose non-zero exit
32	/// the caller can't observe.
33	fn write_failure_marker(params: &FinalizeParams, err: &str) {
34	    let Some(dir) = status_dir() else {
35	        return;
36	    };
37	    if std::fs::create_dir_all(&dir).is_err() {
38	        return;
39	    }
40	    let ns = SystemTime::now()
41	        .duration_since(UNIX_EPOCH)
42	        .map(|d| d.as_nanos())
43	        .unwrap_or(0); // OK: filesystem-sortable timestamp; 0 on the impossible pre-epoch path
44	    let pid = std::process::id();
45	    let path = dir.join(format!("{ns}-{pid}.status"));
46	    let content = format!(
47	        "timestamp_ns={ns}\npid={pid}\nrepo={}\nbookmark={}\nerror={err}\n",
48	        params.repo.display(),
49	        params.bookmark.as_deref().unwrap_or(""),
50	    );
51	    let _ = std::fs::write(&path, content);
52	}
53	
54	/// Read, print, and delete any failure markers left by previous detached
55	/// finalize children. Cheap no-op when the directory doesn't exist.
56	pub fn surface_previous_failures() {
57	    let Some(dir) = status_dir() else {
58	        return;
59	    };
60	    let Ok(entries) = std::fs::read_dir(&dir) else {
61	        return;
62	    };
63	    let mut paths: Vec<PathBuf> = entries
64	        .flatten()
65	        .map(|e| e.path())
66	        .filter(|p| p.extension().and_then(|s| s.to_str()) == Some("status"))
67	        .collect();
68	    paths.sort();
69	    for path in paths {
70	        if let Ok(content) = std::fs::read_to_string(&path) {
71	            eprintln!(
72	                "warn: previous finalize failure ({}):",
73	                path.file_stem()
74	                    .map(|s| s.to_string_lossy())
75	                    .unwrap_or_default() // OK: filename without extension; empty on unexpected absence
76	            );
77	            for line in content.lines() {
78	                eprintln!("  {line}");
79	            }
80	            let _ = std::fs::remove_file(&path);
81	        }
82	    }
83	}
84	
85	/// Squash, set bookmark, and/or push a jj repo.
86	///
87	/// Designed for the bot to atomically finalize its session repo:
88	/// --detach exits immediately, --delay waits for trailing writes,
89	/// --squash folds them in, --bookmark + --push sends it upstream.
90	/// Every flag is opt-in. See README.md for details.
91	#[derive(Args, Debug)]
92	pub struct FinalizeArgs {
93	    /// Path to jj repo
94	    #[arg(long, default_value = ".")]
95	    pub repo: PathBuf,
96	
97	    #[command(flatten)]
98	    pub squash: SquashOption,
99	
100	    /// Seconds to wait before squashing
101	    #[arg(long, default_value_t = 10.0)]
102	    pub delay: f64,
103	
104	    /// Existing bookmark to push to remote
105	    #[arg(long, value_name = "BOOKMARK")]
106	    pub push: Option<String>,
107	
108	    /// Detach and run in the background
109	    #[arg(long)]
110	    pub detach: bool,
111	
112	    /// The above `pub detach` is true when `--detach` is passed
113	    /// to the `finalize` subcommand. The app then `fork`s and
114	    /// and spawns `vc-x1 finalize --exec …`, replacing `--detach`
115	    /// with `--exec`. The child sees `exec: true` and is routed
116	    /// through `finalize_exec()` to do the squash/push work in
117	    /// the background.
118	    ///
119	    /// Marked `hide = true` because it's an internal argument and
120	    /// should not appear in `-h` / `--help` output.
121	    #[arg(long, hide = true)]
122	    pub exec: bool,
123	}
124	
125	/// Per-invocation finalize inputs — the clap-free shape the
126	/// `finalize` op works against. Built from `FinalizeArgs` at the
127	/// binary edge via `TryFrom` (fallible only on repo-path
128	/// canonicalization — `--squash` is already parsed into a
129	/// `SquashSpec` by clap). The `--log` path lives on `Context`,
130	/// not here.
131	#[derive(Debug)]
132	pub struct FinalizeParams {
133	    pub repo: PathBuf,
134	    pub squash: Option<SquashSpec>,
135	    pub delay_secs: f64,
136	    pub bookmark: Option<String>,
137	    pub push: bool,
138	    pub detach: bool,
139	    pub exec: bool,
140	}
141	
142	impl TryFrom<&FinalizeArgs> for FinalizeParams {
143	    type Error = String;
144	
145	    /// Derive `push`/`bookmark` from `--push` and canonicalize
146	    /// `--repo` (so the detached child resolves it regardless of
147	    /// cwd); `--squash` was already parsed by clap.
148	    fn try_from(a: &FinalizeArgs) -> Result<Self, String> {
149	        let repo = std::fs::canonicalize(&a.repo)
150	            .map_err(|e| format!("cannot resolve repo path '{}': {e}", a.repo.display()))?;
151	        Ok(FinalizeParams {
152	            repo,
153	            squash: a.squash.value.clone(),
154	            delay_secs: a.delay,
155	            bookmark: a.push.clone(),
156	            push: a.push.is_some(),
157	            detach: a.detach,
158	            exec: a.exec,
159	        })
160	    }
161	}
162	
163	/// Validate inputs synchronously before detaching.
164	///
165	/// Catches the common failure modes up front so the parent can exit
166	/// with a visible non-zero status — rather than discovering them in
167	/// the detached child where errors only reach the log file.
168	fn preflight(params: &FinalizeParams) -> Result<(), Box<dyn std::error::Error>> {
169	    debug!("preflight: checking params");
170	    let repo_str = params.repo.to_string_lossy();
171	    let cwd = std::path::Path::new(".");
172	
173	    // Verify squash revsets resolve to something.
174	    if let Some(ref sq) = params.squash {
175	        jj_rev_exists(&repo_str, cwd, &sq.source)
176	            .map_err(|e| format!("squash source '{}' does not resolve: {e}", sq.source))?;
177	        jj_rev_exists(&repo_str, cwd, &sq.target)
178	            .map_err(|e| format!("squash target '{}' does not resolve: {e}", sq.target))?;
179	    }
180	
181	    // Refuse to operate on a repo with conflicts.
182	    let conflicts = run(
183	        "jj",
184	        &[
185	            "log",
186	            "-r",
187	            "conflicts()",
188	            "--no-graph",
189	            "-T",
190	            "\"x\"",
191	            "-R",
192	            &repo_str,
193	        ],
194	        cwd,
195	    )?;
196	    if !conflicts.is_empty() {
197	        return Err(format!("repo '{repo_str}' has conflicts — resolve before finalize").into());
198	    }
